package com.company.snackledger.kiosk.config;import java.io.*;import java.nio.file.*;import java.time.Duration;import java.util.*;public record KioskConfig(String serverUrl,String kioskId,String apiKey,boolean fullscreen,int resetSeconds,int connectionTimeoutSeconds,int requestTimeoutSeconds){public static KioskConfig load() throws IOException{Properties p=new Properties();Path path=Paths.get(System.getenv().getOrDefault("SNACKLEDGER_KIOSK_CONFIG","kiosk.properties"));if(Files.exists(path))try(var in=Files.newInputStream(path)){p.load(in);}return new KioskConfig(env("SERVER_URL",p,"server.url","http://localhost:8080"),env("KIOSK_ID",p,"kiosk.id","MAIN-OFFICE-KIOSK"),env("SNACKLEDGER_KIOSK_API_KEY",p,"kiosk.api-key",""),Boolean.parseBoolean(env("KIOSK_FULLSCREEN",p,"kiosk.fullscreen","false")),Integer.parseInt(env("KIOSK_RESET_SECONDS",p,"kiosk.reset-seconds","8")),Integer.parseInt(env("KIOSK_CONNECTION_TIMEOUT_SECONDS",p,"kiosk.connection-timeout-seconds","5")),Integer.parseInt(env("KIOSK_REQUEST_TIMEOUT_SECONDS",p,"kiosk.request-timeout-seconds","15")));}static String env(String e,Properties p,String k,String d){String v=System.getenv(e);if(v!=null&&!v.isBlank())return v;v=p.getProperty(k,d);if(v.startsWith("${")&&v.endsWith("}"))return System.getenv().getOrDefault(v.substring(2,v.length()-1),"");return v;}public Duration connectTimeout(){return Duration.ofSeconds(connectionTimeoutSeconds);}public Duration requestTimeout(){return Duration.ofSeconds(requestTimeoutSeconds);}}
